const ctx=$json.ctx;
const rules='You are the early-warning radar for Tecknuovo, a UK digital-delivery consultancy. Below are the RAW TRANSCRIPTS of the past week\'s client calls, account by account, plus each account\'s recent weekly-report RAG and the risks ALREADY formally flagged. Your ONLY job: find EMERGING concerns that are NOT in already_flagged - things a sharp managing director would want on her radar BEFORE they become formal risks. Look for: hesitation or friction around budgets, renewals or contracts; client-side reorganisations, departures or new decision-makers; repeated small frustrations that add up (delays mentioned in passing, scope confusion, tooling pain); cooling tone or shrinking engagement from client stakeholders; dependencies on things outside our control; anything a client said that sounds like the start of a bigger conversation. Judge from Tecknuovo\'s perspective - a client-side issue matters only if it could affect our delivery, relationship or revenue. RULES: maximum 5 items across all accounts, each ONE sentence naming the account and why it deserves watching, each with a SHORT verbatim quote from the transcript as evidence (copy exactly, max 25 words). Do NOT repeat anything in already_flagged. If nothing genuine is emerging, return an empty items array - never invent. Never use em dashes. Return ONLY JSON: {"items":[{"account":"...","insight":"...","quote":"..."}]}';
const prompt=rules+'\n\nDATA:\n'+JSON.stringify(ctx);
return [{json:{prompt}}];

const raw=($json.text||$json.response||$json.output||'').trim();
const m=raw.match(/\{[\s\S]*\}/); if(!m){return [];}
let obj; try{obj=JSON.parse(m[0]);}catch(e){return [];}
const items=Array.isArray(obj.items)?obj.items.slice(0,5).map(function(x){return {
 account:String((x&&x.account)||'').slice(0,120),
 insight:String((x&&x.insight)||'').slice(0,300),
 quote:String((x&&x.quote)||'').slice(0,220)
}}).filter(function(x){return x.insight}):[];
const e=function(s){return String(s).replace(/'/g,"''")};
const sql="INSERT INTO briefs (audience,period_start,period_end,content) VALUES ('radar', now()::date-7, now()::date, '"+e(JSON.stringify({items:items}))+"'::jsonb);";
return [{json:{sql,found:items.length}}];
